def _research(p: dict[str, Any], d: list[str], e: list[str]) -> DailyOperatorRunComponent:
    latest = _as_dict(p.get("latest")); steps = _as_list(latest.get("steps")); status_val = str(latest.get("status") or p.get("status") or "NOT_PRESENT"); warnings = list(d) + _strings(latest.get("warnings")); blockers = list(e) + _strings(latest.get("blockers")); actions: list[str] = []
    if not latest:
        warnings.append("NO_RESEARCH_OS_OPERATOR_RUN"); actions.append("Run strategy-validator-research-os-run run --overwrite --json to create a digest-linked operator-run manifest.")
    if status_val in {"BLOCKED", "FAILED"}: blockers.append(f"RESEARCH_OS_OPERATOR_RUN_{status_val}")
    if status_val != "COMPLETE": actions.append("Review Research OS run warnings before treating the daily briefing as complete.")
    return _component("research_os_operator_run", "Research OS operator-run manifest", "/ui/research-os/run/latest", "BLOCKED" if blockers else "WARNING" if warnings or status_val != "COMPLETE" else "OK", status_val, {"run_id": latest.get("run_id"), "status": status_val, "trust_banner": latest.get("trust_banner"), "step_count": len(steps), "manifest_path": p.get("manifest_path"), "manifest_sha256": latest.get("manifest_sha256")}, warnings, blockers, actions)


def _status(components: list[DailyOperatorRunComponent]) -> tuple[str, str]:
    if not components: return "EMPTY", "UNTRUSTED"
    if any(c.status == "BLOCKED" for c in components): return "BLOCKED", "UNTRUSTED"
    if any(c.status in {"WARNING", "NOT_PRESENT"} for c in components): return "RESTRICTED", "TRUST_RESTRICTED"
    return "COMPLETE", "TRUSTED"


